function splitAlertConcern(concern: string) {
  return concern.split(",").map((item) => item.trim()).filter(Boolean)
}

function alertConcerns(alert: AlertRecord) {
  return alert.concern_categories?.length ? alert.concern_categories : splitAlertConcern(alert.concern)
}

function sourceTypeLabel(alert: AlertRecord) {
  if (alert.information_source_type === "Other" && alert.information_source_other) return `Other: ${alert.information_source_other}`
  return alert.information_source_type || "Not captured"
}

function submittedByLabel(alert: AlertRecord) {
  return [alert.reporter, alert.reporterType].filter(Boolean).join(", ") || "Not captured"
}

function receivedFromLabel(alert: AlertRecord) {
  const channel = `${alert.reporting_channel || ""} ${alert.intake_source || ""}`.toLowerCase()
  if (channel.includes("public")) {
    if (alert.information_source_reporter_type === "Anonymous" || alert.information_source_type === "Anonymous source") return "Anonymous"
    if (/community case worker|ccw/i.test(alert.reporterType || "")) return submittedByLabel(alert)
    return "Community User"
  }
  return submittedByLabel(alert)
}

function alertOperationalRoute(alert: Pick<AlertRecord, "concern" | "description" | "emergency" | "danger" | "reporting_channel" | "intake_source">) {
  const text = `${alert.concern || ""} ${alert.description || ""} ${alert.reporting_channel || ""} ${alert.intake_source || ""}`.toLowerCase()
  if (alert.emergency || alert.danger.length || /abuse|violence|protection/.test(text)) return "abuse-reports"
  if (/voice|audio/.test(text)) return "voice-reports"
  return "complaints"
}

