function caseStatusFromIntake(status: string): CaseRecord["status"] {
  if (status === "Pending Supervisor Review") return "Pending Supervisor Review"
  if (status === "Approved for Allocation") return "Approved for Allocation"
  if (status === "Allocated to Case Officer") return "Allocated"
  if (status === "Intake Submitted") return "Submitted"
  return "Draft"
}

function districtCodeFromName(districtName: string, districts: DistrictOption[]) {
  return districts.find((district) => district.name === districtName)?.code?.toUpperCase() || ""
}

function caseSequenceParts(reference: string) {
  const parts = reference.split(/[-/]/).filter(Boolean)
  const year = parts.find((part) => /^\d{4}$/.test(part)) || new Date().getFullYear().toString()
  const sequence = [...parts].reverse().find((part) => /^\d+$/.test(part) && part !== year) || "001"
  return { year, sequence: sequence.padStart(4, "0") }
}

function formatCaseNumber(reference: string, districtCode = "") {
  if (/^[A-Z]{3}\/\d{4}\/\d{4,}$/.test(reference)) return reference
  const { year, sequence } = caseSequenceParts(reference)
  return `${districtCode || "PENDING"}/${year}/${sequence}`
}

function displayCaseId(intake: IntakeRecord, districts: DistrictOption[] = []) {
  if (/^[A-Z]{3}\/\d{4}\/\d{4,}$/.test(intake.temporary_case_reference)) return intake.temporary_case_reference
  if (intake.alertReference) {
    const parts = intake.alertReference.split("-")
    return formatCaseNumber(intake.alertReference, parts.length >= 4 ? parts[2] : "")
  }
  const childDraft = intake.child_profile_draft || {}
  const snapshot = intake.original_alert_snapshot || {}
  const opening = intake.opening_summary || {}
  const districtName = textValue(childDraft.district) || textValue(snapshot.district) || nestedTextValue(opening, "district")
  return formatCaseNumber(intake.temporary_case_reference, districtCodeFromName(districtName, districts))
}

function textValue(value: unknown) {
  return typeof value === "string" ? value : value == null ? "" : String(value)
}

function arrayValue(value: unknown): string[] {
  return Array.isArray(value) ? value.map((item) => textValue(item)).filter(Boolean) : []
}

function objectValue(value: unknown): Record<string, unknown> {
  return typeof value === "object" && value !== null && !Array.isArray(value) ? value as Record<string, unknown> : {}
}

function nestedTextValue(source: Record<string, unknown>, key: string) {
  const value = source[key]
  return typeof value === "object" && value !== null ? "" : textValue(value)
}

function hasText(value: unknown) {
  return textValue(value).trim().length > 0
}

function hasManualSummaryData(opening: Record<string, unknown>) {
  return hasText(opening.intake_source) && hasText(opening.district) && hasText(opening.ward)
}

function hasManualOfficerInformantData(opening: Record<string, unknown>) {
  const informant = typeof opening.informant === "object" && opening.informant !== null ? opening.informant as Record<string, unknown> : {}
  return [
    informant.surname,
    informant.first_names,
    informant.phone,
    informant.relationship_to_child,
    informant.organization,
    informant.reporter_type,
  ].some(hasText)
}

function hasManualChildData(childDraft: Record<string, unknown>) {
  const childKnown = textValue(childDraft.known)
  if (!childKnown) return false
  if (childKnown === "No") return hasText(childDraft.age) || hasText(childDraft.current_location)
  return [childDraft.first_names, childDraft.surname, childDraft.age, childDraft.current_location].some(hasText)
}

const HOME_LANGUAGE_OPTIONS = ["English", "Shona", "Ndebele"]
const languageSwitchLabels: Record<SupportedLanguage, string> = {
  en: "English",
  sn: "Shona",
  nd: "Ndebele",
}

function PublicLanguageSwitch({
  value,
  onChange,
  className = "",
  size = "regular",
}: {
  value: string
  onChange: (value: string) => void
  className?: string
  size?: "regular" | "compact" | "nav"
}) {
  const { t } = useTranslation()
  const selectedCode = supportedLanguages.some((language) => language.code === value) ? value : supportedLanguages.find((language) => t(language.labelKey) === value)?.code || "en"
  const shellClass = size === "nav" ? "gap-0 border-[#dce9df] bg-white/95 p-[2px] shadow-none sm:gap-0.5 sm:shadow-[0_4px_12px_rgba(15,23,42,0.055)]" : "gap-1 border-[#d8eadc] bg-white/85 p-1 shadow-sm"
  const buttonClass = size === "nav" ? "h-6 px-1.5 text-[10px] sm:px-2 sm:text-[11px]" : size === "compact" ? "h-7 px-2 text-[11px]" : "h-8 px-2.5 text-xs"
  return (
    <div className={`inline-flex isolate items-center overflow-hidden rounded-full border ${shellClass} ${className}`} aria-label="Select language">
      {supportedLanguages.map((language) => {
        const active = selectedCode === language.code
        return (
          <button
            key={language.code}
            type="button"
            className={`${buttonClass} relative z-10 whitespace-nowrap rounded-full font-extrabold leading-none transition ${active ? "bg-[#0e7a33] text-white shadow-none" : "text-[#52685d] hover:bg-[#f1f8f3] hover:text-[#0e7a33]"}`}
            onClick={() => onChange(language.code)}
          >
            {languageSwitchLabels[language.code]}
          </button>
        )
      })}
    </div>
  )
}

function publicLanguageName(code: string) {
  return code === "sn" ? "Shona" : code === "nd" ? "Ndebele" : "English"
}
const RELIGION_OPTIONS = ["Christian", "Jewish", "Muslim", "Other"]

function hasManualMinimumIntakeData(opening: Record<string, unknown>, childDraft: Record<string, unknown>) {
  return hasManualSummaryData(opening) && hasManualOfficerInformantData(opening) && hasManualChildData(childDraft)
}

function dateInputValue(value: string) {
  const parsed = parseWorkflowDate(value)
  return Number.isNaN(parsed.getTime()) ? "" : parsed.toISOString().slice(0, 10)
}

function isoDateFromLocalDate(date: Date) {
  const year = date.getFullYear()
  const month = `${date.getMonth() + 1}`.padStart(2, "0")
  const day = `${date.getDate()}`.padStart(2, "0")
  return `${year}-${month}-${day}`
}

function calculateAgeFromBirthDate(value: string, now = new Date()) {
  if (!/^\d{4}-\d{2}-\d{2}$/.test(value)) return ""
  const birthDate = new Date(`${value}T00:00:00`)
  if (Number.isNaN(birthDate.getTime()) || birthDate > now) return ""
  let age = now.getFullYear() - birthDate.getFullYear()
  const monthDelta = now.getMonth() - birthDate.getMonth()
  if (monthDelta < 0 || (monthDelta === 0 && now.getDate() < birthDate.getDate())) age -= 1
  return age >= 0 ? `${age}` : ""
}

function estimatedBirthMonthFromAge(ageValue: string, now = new Date()) {
  const age = Number.parseInt(ageValue, 10)
  if (!Number.isFinite(age) || age < 0) return ""
  return `${now.getFullYear() - age}-${`${now.getMonth() + 1}`.padStart(2, "0")}`
}

function estimatedBirthMonthRange(ageValue: string, now = new Date()) {
  const age = Number.parseInt(ageValue, 10)
  if (!Number.isFinite(age) || age < 0) return { min: "", max: "" }
  const minDate = new Date(now.getFullYear() - age - 1, now.getMonth(), now.getDate() + 1)
  const maxDate = new Date(now.getFullYear() - age, now.getMonth(), now.getDate())
  return { min: isoDateFromLocalDate(minDate).slice(0, 7), max: isoDateFromLocalDate(maxDate).slice(0, 7) }
}

function officerDefaults(user: ApiUser) {
  return {
    officer_user_id: `${user.id}`,
    officer_surname: user.last_name || "",
    officer_first_names: user.first_name || user.username || "",
    officer_designation: user.profile.roleLabel || user.profile.role || "",
    officer_district: user.profile.districtName || "",
    officer_contact: user.profile.phone || user.email || "",
  }
}

function caseFromIntake(intake: IntakeRecord, alerts: AlertRecord[], districts: DistrictOption[] = []): CaseRecord {
  const sourceAlert = intake.alertReference ? alerts.find((item) => item.id === intake.alertReference) : undefined
  const childDraft = intake.child_profile_draft || {}
  const snapshot = intake.original_alert_snapshot || {}
  const opening = intake.opening_summary || {}
  const screeningDraft = objectValue(opening.screening_draft)
  const intakeOfficer = [nestedTextValue(opening, "officer_first_names"), nestedTextValue(opening, "officer_surname")].filter(Boolean).join(" ")
  const childName = [textValue(childDraft.first_names), textValue(childDraft.surname)].filter(Boolean).join(" ")
  return {
    id: displayCaseId(intake, districts),
    backendIntakeId: intake.id,
    sourceAlertId: intake.alertReference || undefined,
    intakeDraft: intake,
    childName: sourceAlert?.childName || childName || textValue(childDraft.name) || textValue(snapshot.child_name) || "Unknown child",
    sex: sourceAlert?.sex || textValue(childDraft.sex) || textValue(snapshot.sex) || "Unknown",
    age: sourceAlert?.age || textValue(childDraft.age) || textValue(snapshot.age) || "Unknown",
    district: sourceAlert?.district || textValue(opening.district) || textValue(childDraft.district) || textValue(snapshot.district),
    ward: sourceAlert?.ward || textValue(opening.ward) || textValue(childDraft.ward) || textValue(snapshot.ward),
    concern: intake.case_category || sourceAlert?.concern || textValue(opening.concern_summary) || "Uncategorized",
    riskLevel: intake.risk_level || "Pending",
    status: caseStatusFromIntake(intake.status),
    intakeOfficer: sourceAlert?.intakeOfficer || intakeOfficer || "Intake Officer",
    allocatedOfficer: intake.allocatedOfficerName || undefined,
    allocatedAt: textValue(intake.allocated_at),
    screeningCompletedAt: textValue(intake.screening_completed_at),
    allocationDelaySeconds: intake.allocationDelaySeconds,
    allocationDelayStatus: intake.allocationDelayStatus,
    assessmentStartedAt: intake.assessment_started_at || null,
    assessmentDueAt: intake.assessment_due_at || null,
    assessmentCompletedAt: intake.assessment_completed_at || null,
    assessmentRemainingSeconds: intake.assessmentRemainingSeconds,
    assessmentSlaStatus: intake.assessmentSlaStatus,
    assessmentCarePlanStatus: intake.assessment_care_plan_status,
    assessmentCarePlanSubmittedAt: intake.assessment_care_plan_submitted_at || null,
    caseReviewDueAt: intake.case_review_due_at || null,
    caseReviewStatus: intake.caseReviewStatus,
    closureStatus: intake.closure_status,
    createdAt: intake.created_at,
    submittedForReviewAt: textValue(intake.screening_completed_at) || textValue(screeningDraft.submitted_for_review_at),
    description: intake.immediate_action_plan || sourceAlert?.description || textValue(opening.reporter_narrative) || textValue(snapshot.description),
    background_information: intake.background_information || {},
    prior_assistance: intake.prior_assistance || [],
    manualMinimumComplete: Boolean(intake.alertReference) || hasManualMinimumIntakeData(opening, childDraft),
  }
}

function userDisplayName(user: ApiUser) {
  return [user.first_name, user.last_name].filter(Boolean).join(" ") || user.username
}

function isSupervisorRole(role: string) {
  return ["DISTRICT_HEAD", "PROVINCIAL_HEAD", "SYS_ADMIN", "NATIONAL", "NATIONAL_PROGRAM"].includes(role)
}

function grfmCaseStatus(value = "") {
  const status = value.toLowerCase()
  if (["new", "assigned", "investigation", "awaiting referral response", "escalated", "resolved", "closed", "closure requested"].includes(status)) return value
  if (/closure requested/.test(status)) return "Closure Requested"
  if (/closed|closure approved|referred|rejected|duplicate|resolved|completed|no further action/.test(status)) return "Closed"
  if (/escalated|emergency|immediate|critical/.test(status)) return "Escalated"
  if (/assigned|allocated/.test(status)) return "Assigned"
  if (/referral|referred/.test(status)) return "Awaiting Referral Response"
  if (/progress|review|ready|more information|closure requested|returned|intake|investigation/.test(status)) return "Investigation"
  if (/submitted|received|alert submitted|pending|new/.test(status)) return "New"
  return value || "New"
}

function alertWorkflowType(alert: AlertRecord) {
  const text = `${alert.reporting_channel || ""} ${alert.programme || ""} ${alert.caseCategory || ""} ${alert.concern || ""} ${alert.description || ""}`.toLowerCase()
  if (alert.reporting_channel === "VOICE" || text.includes("voice")) return "Voice"
  if (text.includes("feedback") || text.includes("satisfaction")) return "Feedback"
  if (alert.emergency || alert.danger.length || /abuse|violence|protection|neglect|harm/.test(text)) return "Abuse"
  return "Complaint"
}

function publicSubmissionWorkflowType(submission: PublicSubmissionRecord) {
  if (submission.submission_type === "ABUSE") return "Abuse"
  if (submission.submission_type === "VOICE") return "Voice"
  if (submission.submission_type === "FEEDBACK") return "Feedback"
  return "Complaint"
}

function submissionAssignedToUser(submission: PublicSubmissionRecord, user: ApiUser) {
  return assignedTextMatchesUser(String(submission.metadata?.assignedTo || ""), user)
}

function publicSubmissionAssigned(submission: PublicSubmissionRecord) {
  const assigned = String(submission.metadata?.assignedTo || "").trim()
  return Boolean(assigned && !/^unassigned$/i.test(assigned))
}

function sameOfficer(caseRecord: CaseRecord, user: ApiUser) {
  return assignedTextMatchesUser(caseRecord.allocatedOfficer || "", user)
}

function assignedTextMatchesUser(value: string | undefined, user: ApiUser) {
  const assigned = (value || "").toLowerCase()
  if (!assigned) return false
  const name = userDisplayName(user).toLowerCase()
  const username = user.username.toLowerCase()
  const userId = String(user.id).toLowerCase()
  const firstName = user.first_name.toLowerCase()
  const lastName = user.last_name.toLowerCase()
  return Boolean(
    assigned === name
    || assigned === username
    || assigned === userId
    || assigned.startsWith(`${userId}|`)
    || assigned.includes(name)
    || assigned.includes(username)
    || Boolean(firstName && lastName && assigned.includes(firstName) && assigned.includes(lastName))
  )
}

function alertAssignedToUser(alert: AlertRecord, user: ApiUser) {
  return [alert.allocatedOfficer, alert.intakeOfficer].some((value) => assignedTextMatchesUser(value, user))
}

function alertAssigned(alert: AlertRecord) {
  return [alert.allocatedOfficer, alert.intakeOfficer].some((value) => {
    const assigned = String(value || "").trim()
    return Boolean(assigned && !/^unassigned$/i.test(assigned))
  })
}

function alertEscalationLevel(alert: AlertRecord) {
  const latestEscalation = [...(alert.escalations || [])].reverse().find((item) => item && (item.level || item.escalated_to))
  return String(latestEscalation?.level || latestEscalation?.escalated_to || alert.escalation_level || "")
}

function alertEscalatedToProvince(alert: AlertRecord) {
  return /provinc/i.test(alertEscalationLevel(alert))
}

function alertEscalatedToNational(alert: AlertRecord) {
  return /national/i.test(alertEscalationLevel(alert))
}

function userCanActOnEscalatedAlert(alert: AlertRecord, user: ApiUser) {
  if (user.profile.role === "PROVINCIAL_HEAD") return alertEscalatedToProvince(alert)
  if (["NATIONAL", "NATIONAL_PROGRAM"].includes(user.profile.role)) return alertEscalatedToNational(alert)
  return false
}

function districtScopedRecordVisible(district: string, user: ApiUser) {
  if (!["DISTRICT_HEAD", "DSDO"].includes(user.profile.role)) return true
  if (user.profile.role === "DISTRICT_HEAD" && !user.profile.districtName) return true
  return Boolean(user.profile.districtName && district === user.profile.districtName)
}

function notificationPriorityRank(priority: WorkflowNotification["priority"]) {
  return { escalated: 0, critical: 1, warning: 2, info: 3 }[priority]
}

function mergeWorkflowNotifications(derived: WorkflowNotification[], backend: WorkflowNotification[]) {
  const importantBackend = backend.filter((item) => !item.resolvedAt && (item.priority !== "info" || item.category === "Closure"))
  const merged = new Map<string | number, WorkflowNotification>()
  ;[...derived, ...importantBackend].forEach((item) => {
    const key = `${item.targetType}:${item.targetId}:${item.category}:${item.title}`
    merged.set(key, item)
  })
  return Array.from(merged.values()).sort((a, b) => {
    const priority = notificationPriorityRank(a.priority) - notificationPriorityRank(b.priority)
    if (priority !== 0) return priority
    return parseWorkflowDate(b.createdAt).getTime() - parseWorkflowDate(a.createdAt).getTime()
  })
}

function buildWorkflowNotifications(user: ApiUser, alerts: AlertRecord[], cases: CaseRecord[]) {
  const role = user.profile.role
  const isSupervisor = isSupervisorRole(role)
  const userDistrict = user.profile.districtName || ""
  const now = Date.now()
  const inScope = (district: string) => !userDistrict || district === userDistrict || !["DISTRICT_HEAD", "DSDO"].includes(role)
  const notes: WorkflowNotification[] = []

  alerts.forEach((alert) => {
    if (!inScope(alert.district)) return
    const status = alert.internalStatus || alert.status
    if (isSupervisor && ["Alert Submitted", "Received by District Office", "Under Review", "Submitted"].includes(status)) {
      notes.push({
        id: `alert-${alert.id}-intake-allocation`,
        title: "Submitted intake needs attention",
        message: `${alert.id} is waiting for district review or conversion.`,
        category: "Intake",
        priority: alert.emergency ? "critical" : "warning",
        targetType: "alert",
        targetId: alert.id,
        actionLabel: "Open alert",
        createdAt: alert.submittedAt,
        route: "triage",
        unread: true,
      })
    }
    if (isSupervisor && alert.emergency && !["Converted to Case", "Closed - No Further Action", "Rejected", "Closed - Invalid"].includes(status)) {
      notes.push({
        id: `alert-${alert.id}-emergency`,
        title: "Emergency alert active",
        message: `${alert.childName || "Child"} has an emergency alert requiring visible action.`,
        category: "Alert",
        priority: "critical",
        targetType: "alert",
        targetId: alert.id,
        actionLabel: "Review emergency",
        createdAt: alert.submittedAt,
        route: "triage",
        unread: true,
      })
    }
  })

  cases.filter((caseRecord) => !isEmptyManualPlaceholder(caseRecord) && inScope(caseRecord.district)).forEach((caseRecord) => {
    const assignedToUser = role === "DSDO" && sameOfficer(caseRecord, user)
    const createdAt = caseRecord.allocatedAt || caseRecord.submittedForReviewAt || caseRecord.createdAt
    if (assignedToUser && caseRecord.status === "Allocated") {
      notes.push({
        id: `case-${caseRecord.id}-allocated`,
        title: "Case allocated to you",
        message: `${caseRecord.id} has been allocated to you for assessment and follow-up.`,
        category: "Allocation",
        priority: ["HIGH", "CRITICAL"].includes(caseRecord.riskLevel.toUpperCase()) ? "critical" : "info",
        targetType: "case",
        targetId: caseRecord.id,
        actionLabel: "Open case",
        createdAt,
        route: "case-intake",
        unread: true,
      })
    }
    if (isSupervisor && caseRecord.status === "Pending Supervisor Review") {
      notes.push({
        id: `case-${caseRecord.id}-screening-review`,
        title: "Intake submitted for review",
        message: `${caseRecord.id} is waiting for supervisor screening review.`,
        category: "Intake",
        priority: "warning",
        targetType: "case",
        targetId: caseRecord.id,
        actionLabel: "Review intake",
        createdAt: caseRecord.submittedForReviewAt || createdAt,
        route: "review",
        unread: true,
      })
    }
    if (isSupervisor && caseRecord.status === "Approved for Allocation") {
      notes.push({
        id: `case-${caseRecord.id}-allocation-ready`,
        title: "Case needs allocation",
        message: `${caseRecord.id} is approved and needs assignment to a DSDO.`,
        category: "Allocation",
        priority: "warning",
        targetType: "case",
        targetId: caseRecord.id,
        actionLabel: "Allocate case",
        createdAt,
        route: "allocation",
        unread: true,
      })
    }
    if ((assignedToUser || isSupervisor) && caseRecord.assessmentDueAt && !caseRecord.assessmentCompletedAt) {
      const due = parseWorkflowDate(caseRecord.assessmentDueAt)
      const remainingMs = due.getTime() - now
      if (Number.isFinite(remainingMs) && remainingMs <= 48 * 60 * 60 * 1000) {
        notes.push({
          id: `case-${caseRecord.id}-assessment-due`,
          title: remainingMs < 0 ? "Assessment overdue" : "Assessment due soon",
          message: remainingMs < 0 ? `${caseRecord.id} assessment is overdue by ${formatDuration(Math.floor(Math.abs(remainingMs) / 1000))}.` : `${caseRecord.id} assessment is due ${relativeDueDateLabel(caseRecord.assessmentDueAt)}.`,
          category: "Assessment",
          priority: remainingMs < 0 ? (isSupervisor ? "escalated" : "critical") : "warning",
          targetType: "case",
          targetId: caseRecord.id,
          actionLabel: "Open assessment",
          createdAt,
          dueAt: caseRecord.assessmentDueAt,
          route: assignedToUser ? "case-intake" : "allocated-cases",
          unread: true,
        })
      }
    }
    if (isSupervisor && caseRecord.assessmentCarePlanStatus === "Submitted") {
      notes.push({
        id: `case-${caseRecord.id}-care-plan-review`,
        title: "Assessment and care plan submitted",
        message: `${caseRecord.id} is waiting for supervisor assessment and care plan review.`,
        category: "Care Plan",
        priority: "warning",
        targetType: "case",
        targetId: caseRecord.id,
        actionLabel: "Open submission",
        createdAt,
        route: "allocated-cases",
        unread: true,
      })
    }
  })

  const unique = new Map(notes.map((item) => [item.id, item]))
  return Array.from(unique.values()).sort((a, b) => {
    const priority = notificationPriorityRank(a.priority) - notificationPriorityRank(b.priority)
    if (priority !== 0) return priority
    return parseWorkflowDate(b.createdAt).getTime() - parseWorkflowDate(a.createdAt).getTime()
  })
}

