            <button className="inline-flex h-9 items-center rounded-full border border-[#cfe8d0] bg-[#f1f8f3] px-4 text-sm font-extrabold text-[#0e7a33] hover:bg-[#e7f4eb]" onClick={onTrack}>{t("home.viewAllReports")}</button>
