function AdminTablePagination({
  totalRows,
  page,
  pageCount,
  pageStart,
  pageEnd,
  rowsPerPage,
  onRowsPerPageChange,
  onPageChange,
}: {
  totalRows: number
  page: number
  pageCount: number
  pageStart: number
  pageEnd: number
  rowsPerPage: number
  onRowsPerPageChange: (value: number) => void
  onPageChange: (value: number) => void
}) {
  return (
    <div className="flex flex-wrap items-center justify-between gap-3 border-t border-slate-700/80 bg-slate-950/30 px-4 py-3 text-sm font-bold text-slate-400">
      <div className="flex flex-wrap items-center gap-3">
        <span>Showing <span className="text-slate-100">{pageStart}-{pageEnd}</span> of <span className="text-slate-100">{totalRows}</span></span>
        <label className="flex items-center gap-2">
          Rows
          <select className="h-9 rounded-lg border border-slate-700 bg-slate-950/45 px-2 text-sm font-extrabold text-slate-100 outline-none focus:border-[#16A34A]" value={rowsPerPage} onChange={(event) => onRowsPerPageChange(Number(event.target.value))}>
            {[10, 25, 50].map((count) => <option key={count} value={count}>{count}</option>)}
          </select>
        </label>
      </div>
      <div className="flex items-center gap-2">
        <button className="h-9 rounded-lg border border-slate-700 bg-slate-950/45 px-3 text-sm font-extrabold text-slate-200 disabled:cursor-not-allowed disabled:opacity-40 hover:border-[#16A34A] hover:text-[#86efac]" disabled={page <= 1} onClick={() => onPageChange(Math.max(1, page - 1))}>Prev</button>
        <span className="rounded-lg bg-slate-900 px-3 py-2 text-xs font-extrabold text-slate-300 ring-1 ring-slate-700">Page {page} of {pageCount}</span>
        <button className="h-9 rounded-lg border border-slate-700 bg-slate-950/45 px-3 text-sm font-extrabold text-slate-200 disabled:cursor-not-allowed disabled:opacity-40 hover:border-[#16A34A] hover:text-[#86efac]" disabled={page >= pageCount} onClick={() => onPageChange(Math.min(pageCount, page + 1))}>Next</button>
      </div>
    </div>
  )
}

function paginateAdminRows<T>(rows: T[], page: number, rowsPerPage: number) {
  const pageCount = Math.max(1, Math.ceil(rows.length / rowsPerPage))
  const safePage = Math.min(Math.max(1, page), pageCount)
  const startIndex = (safePage - 1) * rowsPerPage
  const pageStart = rows.length ? startIndex + 1 : 0
  const pageEnd = Math.min(startIndex + rowsPerPage, rows.length)
  return {
    rows: rows.slice(startIndex, startIndex + rowsPerPage),
    pageCount,
    safePage,
    pageStart,
    pageEnd,
  }
}

