function adminDaysOpen(dateValue?: string) {
  if (!dateValue) return "0"
  const time = new Date(dateValue).getTime()
  if (!Number.isFinite(time)) return "0"
  return String(Math.max(0, Math.floor((Date.now() - time) / 86400000)))
}

